contracts/AnonymousMail.sol.content:
// SPDX-License-Identifier: UNLICENSED
pragma solidity ^0.8.26;

import {IIdentityRegistry} from "./interfaces/IIdentityRegistry.sol";

/// @title AnonymousMail
/// @notice On-chain anonymous mailbox. The headline privacy property is visible
///         directly in the storage layout: **there is no sender field anywhere**.
///
///         A user encrypts a message to the recipient's key, hands the sealed
///         blob to an Acurast TEE relay (see ACURAST.md), and the relay submits
///         it here. Because submission goes through a relayer set, `msg.sender`
///         is the relay — never the author — so the author is unlinkable from
///         the chain's perspective. The relay runs inside a hardware Trusted
///         Execution Environment, so not even the relay operator learns the
///         author. Content lives on the Bulletin Chain and is pruned at TTL.
///
///         This contract is intentionally minimal and auditable: a reviewer can
///         confirm in one read that no metadata can leak a sender.
contract AnonymousMail {
    IIdentityRegistry public immutable identity;
    address public owner;

    /// @notice Authorized Acurast TEE relays allowed to deliver mail.
    mapping(address => bool) public relayer;

    struct Mail {
        string cid; // Bulletin Chain CID of the sealed payload ("" once burned)
        uint64 deliveredAt;
        uint64 expiresAt; // Bulletin retention deadline (0 = none)
        bool read;
        bool burned;
        // NOTE: deliberately no `from`. Sender anonymity is structural.
    }

    mapping(address => Mail[]) private _inbox;

    event MailDelivered(address indexed to, uint256 indexed index, string cid, uint64 expiresAt);
    event MailRead(address indexed to, uint256 indexed index);
    event MailBurned(address indexed to, uint256 indexed index);
    event RelayerSet(address indexed relay, bool allowed);

    error NotOwner();
    error NotRelayer();
    error RecipientNotRegistered();
    error BadIndex();

    modifier onlyOwner() {
        if (msg.sender != owner) revert NotOwner();
        _;
    }

    constructor(address identityRegistry) {
        owner = msg.sender;
        identity = IIdentityRegistry(identityRegistry);
    }

    function setRelayer(address relay, bool allowed) external onlyOwner {
        relayer[relay] = allowed;
        emit RelayerSet(relay, allowed);
    }

    /// @notice Deliver sealed mail to `to`. Callable only by an authorized relay.
    function deliver(address to, string calldata cid, uint64 expiresAt)
        external
        returns (uint256 index)
    {
        if (!relayer[msg.sender]) revert NotRelayer();
        if (!identity.isRegistered(to)) revert RecipientNotRegistered();
        index = _inbox[to].length;
        _inbox[to].push(Mail({
            cid: cid,
            deliveredAt: uint64(block.timestamp),
            expiresAt: expiresAt,
            read: false,
            burned: false
        }));
        emit MailDelivered(to, index, cid, expiresAt);
    }

    function markRead(uint256 index) external {
        Mail[] storage box = _inbox[msg.sender];
        if (index >= box.length) revert BadIndex();
        box[index].read = true;
        emit MailRead(msg.sender, index);
    }

    /// @notice Recipient destroys the on-chain pointer; the Bulletin blob is left
    ///         to lapse and is pruned at retention end.
    function burn(uint256 index) external {
        Mail[] storage box = _inbox[msg.sender];
        if (index >= box.length) revert BadIndex();
        box[index].burned = true;
        box[index].cid = "";
        emit MailBurned(msg.sender, index);
    }

    function inboxCount(address account) external view returns (uint256) {
        return _inbox[account].length;
    }

    function getInbox(address account, uint256 offset, uint256 limit)
        external
        view
        returns (Mail[] memory page)
    {
        Mail[] storage box = _inbox[account];
        if (offset >= box.length) return new Mail[](0);
        uint256 end = offset + limit;
        if (end > box.length) end = box.length;
        page = new Mail[](end - offset);
        for (uint256 i = offset; i < end; i++) {
            page[i - offset] = box[i];
        }
    }
}

contracts/IdentityRegistry.sol.content:
// SPDX-License-Identifier: UNLICENSED
pragma solidity ^0.8.26;

import {IIdentityRegistry} from "./interfaces/IIdentityRegistry.sol";

/// @title IdentityRegistry
/// @notice Root of the Umbra contract network. Maps each account to an X25519
///         encryption public key and to the Bulletin Chain CID of its profile.
///         Messenger and Payments read from here to know how to encrypt messages
///         and to enforce proof-of-personhood anti-spam rules.
contract IdentityRegistry is IIdentityRegistry {
    mapping(address => Profile) private _profiles;

    /// @notice Account authorized to attest personhood (Individuality oracle).
    ///         In production this is the bridge to Polkadot's Individuality pallet.
    address public personhoodAttester;
    address public owner;

    event Registered(address indexed account, bytes32 encryptionPubKey, string profileCid);
    event ProfileUpdated(address indexed account, string profileCid);
    event PersonhoodAttested(address indexed account, bool personhood);

    error NotOwner();
    error NotAttester();
    error EmptyKey();

    modifier onlyOwner() {
        if (msg.sender != owner) revert NotOwner();
        _;
    }

    constructor(address attester) {
        owner = msg.sender;
        personhoodAttester = attester;
    }

    /// @notice Register or update the caller's encryption key + profile.
    function register(bytes32 encryptionPubKey, string calldata profileCid) external {
        if (encryptionPubKey == bytes32(0)) revert EmptyKey();

        Profile storage p = _profiles[msg.sender];
        bool isNew = p.registeredAt == 0;

        p.encryptionPubKey = encryptionPubKey;
        p.profileCid = profileCid;
        if (isNew) {
            p.registeredAt = uint64(block.timestamp);
        }

        emit Registered(msg.sender, encryptionPubKey, profileCid);
    }

    /// @notice Update only the profile CID (avatar/name on the Bulletin Chain).
    function updateProfile(string calldata profileCid) external {
        Profile storage p = _profiles[msg.sender];
        require(p.registeredAt != 0, "not registered");
        p.profileCid = profileCid;
        emit ProfileUpdated(msg.sender, profileCid);
    }

    /// @notice Personhood attestation from the Individuality oracle.
    function attestPersonhood(address account, bool value) external {
        if (msg.sender != personhoodAttester) revert NotAttester();
        _profiles[account].personhood = value;
        emit PersonhoodAttested(account, value);
    }

    function setAttester(address attester) external onlyOwner {
        personhoodAttester = attester;
    }

    // ── IIdentityRegistry ──────────────────────────────────────────────────────

    function isRegistered(address account) external view returns (bool) {
        return _profiles[account].registeredAt != 0;
    }

    function profileOf(address account) external view returns (Profile memory) {
        return _profiles[account];
    }

    function encryptionKeyOf(address account) external view returns (bytes32) {
        return _profiles[account].encryptionPubKey;
    }
}

contracts/Individuality.sol.content:
// SPDX-License-Identifier: UNLICENSED
pragma solidity ^0.8.26;

import {IIndividuality} from "./interfaces/IIndividuality.sol";

/// @title IRingVrfVerifier
/// @notice Verifies a ring-VRF proof: that a contextual alias + nullifier were
///         produced by *some* member of the registered people set (`peopleRoot`)
///         for a given `context`, without revealing which member. In production
///         this wraps the verifier exported by the Polkadot People Chain.
interface IRingVrfVerifier {
    function verify(
        bytes32 peopleRoot,
        bytes32 context,
        address aliasAccount,
        bytes32 nullifier,
        bytes calldata proof
    ) external view returns (bool);
}

/// @title Individuality
/// @notice On-chain mirror / consumer of Polkadot's **Project Individuality**
///         (the People Chain), modeled as Gavin Wood imagined it:
///
///         - **Contextual aliases.** A registered human derives a *different,
///           unlinkable* alias per context (app/channel/service) via a ring-VRF.
///           You never present the same pseudonym twice across contexts.
///         - **Nullifiers.** Each (person, context) yields one deterministic
///           nullifier, so a person can hold **at most one alias per context** —
///           Sybil resistance without identity, without KYC.
///         - **DIMs.** Assurance comes in levels: DIM1 (Proof of Individuality,
///           uniqueness — fine for low-risk gating like channels) and DIM2
///           (Proof of Verified Individuality — for high-value actions).
///         - **People root.** `peopleRoot` commits to the set of registered
///           unique humans on the People Chain, updated by an OpenGov-controlled
///           bridge. The actual ring/zk lives on the People Chain; this contract
///           verifies proofs against the root and tracks per-context aliases.
contract Individuality is IIndividuality {
    address public owner;
    /// @notice OpenGov-controlled bridge that publishes the People Chain root.
    address public peopleChainBridge;
    /// @notice Commitment to the registered set of unique humans.
    bytes32 public peopleRoot;
    IRingVrfVerifier public verifier;

    struct Alias {
        uint8 dim; // 1 = DIM1, 2 = DIM2
        uint64 since;
        bool active;
    }

    // context => alias account => alias record
    mapping(bytes32 => mapping(address => Alias)) private _aliases;
    // context => nullifier => used (enforces one alias per person per context)
    mapping(bytes32 => mapping(bytes32 => bool)) public nullifierUsed;

    event PeopleRootUpdated(bytes32 root);
    event AliasRegistered(bytes32 indexed context, address indexed aliasAccount, bytes32 nullifier, uint8 dim);
    event AliasRevoked(bytes32 indexed context, address indexed aliasAccount);

    error NotOwner();
    error NotBridge();
    error BadDim();
    error NullifierUsed();
    error BadProof();

    modifier onlyOwner() {
        if (msg.sender != owner) revert NotOwner();
        _;
    }

    constructor(address ringVrfVerifier) {
        owner = msg.sender;
        peopleChainBridge = msg.sender;
        verifier = IRingVrfVerifier(ringVrfVerifier);
    }

    function setPeopleRoot(bytes32 root) external {
        if (msg.sender != peopleChainBridge) revert NotBridge();
        peopleRoot = root;
        emit PeopleRootUpdated(root);
    }

    function setBridge(address bridge) external onlyOwner {
        peopleChainBridge = bridge;
    }

    function setVerifier(address ringVrfVerifier) external onlyOwner {
        verifier = IRingVrfVerifier(ringVrfVerifier);
    }

    /// @notice Register a contextual alias. `msg.sender` is the freshly-derived,
    ///         unlinkable alias account for `context`. `nullifier` is the ring-VRF
    ///         output bound to (person, context); it is deterministic per person,
    ///         so a second registration in the same context is rejected.
    /// @param dim Requested assurance level (1 or 2); the proof must support it.
    function registerAlias(bytes32 context, bytes32 nullifier, uint8 dim, bytes calldata proof) external {
        if (dim != 1 && dim != 2) revert BadDim();
        if (nullifierUsed[context][nullifier]) revert NullifierUsed();
        if (!verifier.verify(peopleRoot, context, msg.sender, nullifier, proof)) revert BadProof();

        nullifierUsed[context][nullifier] = true;
        _aliases[context][msg.sender] = Alias({dim: dim, since: uint64(block.timestamp), active: true});
        emit AliasRegistered(context, msg.sender, nullifier, dim);
    }

    /// @notice Voluntarily retire an alias from a context (you keep your humanity,
    ///         not this pseudonym). The nullifier stays spent — no re-aliasing.
    function revokeAlias(bytes32 context) external {
        _aliases[context][msg.sender].active = false;
        emit AliasRevoked(context, msg.sender);
    }

    // ── IIndividuality ─────────────────────────────────────────────────────────

    function isUnique(bytes32 context, address account) external view returns (bool) {
        return _aliases[context][account].active;
    }

    function dimOf(bytes32 context, address account) external view returns (uint8) {
        Alias storage a = _aliases[context][account];
        return a.active ? a.dim : 0;
    }
}

/// @title MockRingVrfVerifier
/// @notice Demo/test verifier that accepts any well-formed claim. In production
///         this is replaced by the real ring-VRF verifier from the People Chain.
///         Kept separate and obviously named so no one mistakes it for the real
///         thing.
contract MockRingVrfVerifier is IRingVrfVerifier {
    function verify(bytes32, bytes32, address, bytes32, bytes calldata)
        external
        pure
        returns (bool)
    {
        return true;
    }
}

